return ['x-generator'=>'GlotPress/4.0.3','translation-revision-date'=>'2026-03-27 08:59:49+0000','plural-forms'=>'nplurals=3; plural=(n % 10 == 1 && n % 100 != 11) ? 0 : ((n % 10 >= 2 && n % 10 <= 4 && (n % 100 < 12 || n % 100 > 14)) ? 1 : 2);','project-id-version'=>'Plugins - Akismet Anti-spam: Spam Protection - Stable (latest release)','language'=>'hr','messages'=>['Get started'=>'Započnite','Name your own price for personal sites. Businesses start on a paid plan.'=>'Odredite vlastitu cijenu za osobne web-stranice. Tvrtke počinju s plaćenim planom.','Flexible pricing'=>'Fleksibilno određivanje cijena','Seamlessly integrates with plugins like Elementor, Contact Form 7, Jetpack and WPForms.'=>'Besprijekorno se integrira s dodacima poput Elementora, Contact Form 7, Jetpacka i WPFormsa.','Works with popular contact forms'=>'Radi s popularnim kontakt obrascima','Akismet runs quietly in the background, saving you hours of manual moderation.'=>'Akismet tiho radi u pozadini, štedeći vam sate ručnog moderiranja.','Zero effort'=>'Bez napora','Learns from billions of spam signals across the web to stop junk before it reaches you.'=>'Uči iz milijardi neželjenih signala diljem weba kako bi zaustavio neželjenu poštu prije nego što dođe do vas.','Machine learning accuracy'=>'Točnost strojnog učenja','Protect your site from comment spam and contact form spam — automatically.'=>'Zaštitite svoju web-stranicu od neželjenih komentara i neželjenih obrazaca za kontakt — automatski.','Want to use a different account? <a href="%s" class="akismet-external-link">Visit akismet.com</a> to set it up and get your API key.'=>'Želite li koristiti drugi račun? <a href="%s" class="akismet-external-link">Posjetite akismet.com</a> da biste ga postavili i dobili svoj API ključ.','By connecting, we\'ll use your Jetpack account to activate Akismet on this site.'=>'Povezivanjem ćemo koristiti vaš Jetpack račun za aktivaciju Akismeta na ovoj web-stranici.','Contact support'=>'Kontaktirajte podršku','Your Akismet account appears to be suspended. This sometimes happens if there\'s a billing or verification issue. Please contact our support team so we can help you get it sorted.'=>'Čini se da je vaš Akismet račun suspendiran. To se ponekad događa ako postoji problem s naplatom ili provjerom. Obratite se našem timu za podršku kako bismo vam mogli pomoći da to riješite.','Choose a plan on Akismet.com'=>'Odaberite plan na Akismet.com','Your Jetpack account is connected, but it doesn\'t have an active Akismet subscription yet. To continue, please choose a plan on Akismet.com.'=>'Vaš Jetpack račun je povezan, ali još nema aktivnu Akismet pretplatu. Za nastavak odaberite plan na Akismet.com.','Signed in as %s'=>'Prijavljeni ste kao %s','Increase your limit'=>'Povećajte svoje ograničenje','Add an %s subscription'=>'Dodajte %s pretplatu','Your Akismet usage has been over your plan&#8217;s limit for two consecutive months. Next month, we will restrict your account after you reach the limit. Increase your limit to make sure your site stays protected from spam.'=>'Vaša upotreba Akismeta premašuje limit vašeg plana dva mjeseca zaredom. Sljedeći mjesec ćemo ograničiti vaš račun nakon što dosegnete limit. Povećajte limit kako biste osigurali da vaša web-stranica ostane zaštićena od spama.','Please enter a new key or <a class="akismet-external-link" href="%s" target="_blank">contact Akismet support</a>'=>'Unesite novi ključ ili <a class="akismet-external-link" href="%s" target="_blank">kontaktirajte Akismet podršku</a>','Once you\'ve chosen a plan, return here to complete your setup.'=>'Nakon što odaberete plan, vratite se ovdje kako biste dovršili postavljanje.','Please <a class="akismet-external-link" href="%s" target="_blank">choose a free or paid plan</a> so Akismet can protect your site from spam.'=>'Molimo <a class="akismet-external-link" href="%s" target="_blank">odaberite besplatni ili plaćeni plan</a> kako bi Akismet mogao zaštititi vašu web-stranicu od spama.','You can help us fight spam and upgrade your account by <a class="akismet-external-link" href="%s" target="_blank">contributing a token amount</a>'=>'Možete nam pomoći u borbi protiv spama i nadograditi svoj račun <a class="akismet-external-link" href="%s" target="_blank">doprinosom iznosa tokena</a>','Please contact <a class="akismet-external-link" href="%s" target="_blank">Akismet support</a> for assistance.'=>'Za pomoć kontaktirajte <a class="akismet-external-link" href="%s" target="_blank">Akismet podršku</a>.','Please visit <a class="akismet-external-link" href="%s" target="_blank">Akismet.com</a> to purchase a new subscription.'=>'Posjetite <a class="akismet-external-link" href="%s" target="_blank">Akismet.com</a> kako biste kupili novu pretplatu.','Please contact your web host or firewall administrator and give them <a class="akismet-external-link" href="%s" target="_blank">this information about Akismet&#8217;s system requirements</a>'=>'Obratite se administratoru svog web hostinga ili vatrozida i dajte im <a class="akismet-external-link" href="%s" target="_blank">ove informacije o Akismetovim sistemskim zahtjevima</a>','Your web host or server administrator has disabled PHP&#8217;s <code>gethostbynamel</code> function.'=>'Vaš administrator web hostinga ili poslužitelja onemogućio je PHP-ovu funkciju <code>gethostbynamel</code>.','For more information, see the <a class="akismet-external-link" href="%s">error documentation on akismet.com</a>'=>'Za više informacija pogledajte <a class="akismet-external-link" href="%s">dokumentaciju o greškama na akismet.com</a>','If you believe your site should not be classified as commercial, <a class="akismet-external-link" href="%s">please get in touch</a>'=>'Ako smatrate da vaša web-stranica ne bi trebala biti klasificirana kao komercijalna, <a class="akismet-external-link" href="%s">molimo vas da nas kontaktirate</a>','Your current subscription is for <a class="akismet-external-link" href="%s">personal, non-commercial use</a>. Please